import 'package:flutter/material.dart';import 'package:provider/provider.dart';import '../../design_system/app_colors.dart';import '../../design_system/app_spacing.dart';import '../../design_system/app_typography.dart';import '../../design_system/ds_buttons.dart';import '../../design_system/ds_card.dart';import '../../design_system/ds_input_field.dart';import '../../models/transaction.dart';import '../../providers/insights_provider.dart';import '../../services/mock_data_service.dart';import 'category_selector_screen.dart';class TransactionDetailScreen extends StatefulWidget {  final Transaction transaction;  const TransactionDetailScreen({super.key, required this.transaction});  @override  State<TransactionDetailScreen> createState() => _TransactionDetailScreenState();}@overrideclass _TransactionDetailScreenState extends State<TransactionDetailScreen> {  late Transaction _currentTransaction;  @override  void initState() {    super.initState();    _currentTransaction = widget.transaction;  }  Future<void> _selectCategory(BuildContext context) async {    final selectedCategory = await Navigator.of(context).push<CategorySelectorScreenResult>(      MaterialPageRoute(builder: (_) => const CategorySelectorScreen()),    );    if (selectedCategory != null && selectedCategory.category != null) {      setState(() {        _currentTransaction =            _currentTransaction.copyWith(category: selectedCategory.category);      });      // Optionally save immediately or wait for a 'Save' button      Provider.of<InsightsProvider>(context, listen: false)          .updateTransaction(_currentTransaction);    }  }  void _attachReceipt() {    // TODO: Implement Receipt Capture (Camera UI)    ScaffoldMessenger.of(context).showSnackBar(      const SnackBar(content: Text('Receipt capture coming soon!')),    );  }  void _saveTransaction() {    Provider.of<InsightsProvider>(context, listen: false)        .updateTransaction(_currentTransaction);    ScaffoldMessenger.of(context).showSnackBar(      const SnackBar(content: Text('Transaction updated!')),    );    Navigator.of(context).pop();  }  @override  Widget build(BuildContext context) {    final isNegative = _currentTransaction.amount < 0;    return Scaffold(      backgroundColor: AppColors.background,      appBar: AppBar(        title: Text('Transaction Detail', style: AppTypography.h2),        actions: [          DsIconButton(            icon: Icons.edit_outlined,            onPressed: () {              ScaffoldMessenger.of(context).showSnackBar(                const SnackBar(content: Text('Edit Transaction coming soon!')),              );            },          ),          SizedBox(width: AppSpacing.paddingSmall),        ],      ),      body: ListView(        padding: AppSpacing.screenPadding,        children: [          DsCard(            child: Column(              crossAxisAlignment: CrossAxisAlignment.start,              children: [                Text(                  _currentTransaction.merchant,                  style: AppTypography.h1,                ),                SizedBox(height: AppSpacing.paddingSmall),                Text(                  MockDataService.formatCurrency(_currentTransaction.amount),                  style: AppTypography.h1.copyWith(                    color: isNegative ? AppColors.error : AppColors.success,                  ),                ),                SizedBox(height: AppSpacing.paddingSmall),                Text(                  '${_currentTransaction.date.day}/${_currentTransaction.date.month}/${_currentTransaction.date.year}',                  style: AppTypography.body.copyWith(color: AppColors.textSecondary),                ),              ],            ),          ),          SizedBox(height: AppSpacing.paddingLarge),          DsInputField(            labelText: 'Category',            hintText: 'Select Category',            readOnly: true,            controller: TextEditingController(text: _currentTransaction.category.name),            onTap: () => _selectCategory(context),            suffixIcon: Icon(Icons.arrow_forward_ios,                color: AppColors.textSecondary, size: AppSpacing.iconSizeMedium / 1.5),          ),          SizedBox(height: AppSpacing.paddingMedium),          DsInputField(            labelText: 'Tags',            hintText: 'Add tags (e.g., #travel, #work)',            controller: TextEditingController(text: _currentTransaction.tags.join(', ')),            onChanged: (value) {              setState(() {                _currentTransaction = _currentTransaction.copyWith(                  tags: value.split(',').map((e) => e.trim()).where((e) => e.isNotEmpty).toList(),                );              });            },          ),          SizedBox(height: AppSpacing.paddingMedium),          DsCard(            child: Column(              crossAxisAlignment: CrossAxisAlignment.start,              children: [                Text('Receipt', style: AppTypography.body),                SizedBox(height: AppSpacing.paddingSmall),                _currentTransaction.receiptImageUrl != null                    ? Image.network(_currentTransaction.receiptImageUrl!)                    : DsSecondaryButton(                        text: 'Attach Receipt',                        onPressed: _attachReceipt,                      ),              ],            ),          ),          SizedBox(height: AppSpacing.paddingLarge),          DsPrimaryButton(            text: 'Save Changes',            onPressed: _saveTransaction,          ),          SizedBox(height: AppSpacing.paddingSmall),          DsSecondaryButton(            text: 'Report Categorization Error',            onPressed: () {              ScaffoldMessenger.of(context).showSnackBar(                const SnackBar(content: Text('Reporting error...')),              );            },          ),        ],      ),    );  }}